+            | Self::HashPartition { .. }
+            | Self::WildcardCapture { .. }
+            | Self::DeterministicHash { .. }
+            | Self::SplitSlice { .. }
+            | Self::LeftExtract { .. }
+            | Self::RightExtract { .. } => Ok(()),
