+    children: BTreeMap<String, TrieNode>,
+    /// Single-wildcard (`*`) child.
+    wildcard_child: Option<Box<TrieNode>>,
+    /// Tail-wildcard (`>`) leaf subscribers.
+    tail_subscribers: Vec<Subscriber>,
+    /// Exact-match leaf subscribers (no further tokens).
