+        self.leaf_subscribers.retain(|sub| sub.id != id);
+        if self.leaf_subscribers.len() != before {
+            removed = true;
+        }
+
+        let before = self.tail_subscribers.len();
+        self.tail_subscribers.retain(|sub| sub.id != id);
+        if self.tail_subscribers.len() != before {
+            removed = true;
+        }
+
+        removed
+    }
+}
