+        let gen0 = sl.generation();
+
+        let guard = sl.subscribe(&SubjectPattern::new("test"), None);
+        let gen1 = sl.generation();
+        assert!(gen1 > gen0);
+
+        drop(guard);
+        let gen2 = sl.generation();
+        assert!(gen2 > gen1);
+    }
