+        let _g2 = sl.subscribe(&SubjectPattern::new("orders.>"), None);
+
+        let handles: Vec<_> = (0..4)
+            .map(|_| {
+                let sl_clone = Arc::clone(&sl);
+                thread::spawn(move || {
