+        let g3 = sl.subscribe(&SubjectPattern::new("c"), None);
+
+        assert_ne!(g1.id(), g2.id());
+        assert_ne!(g2.id(), g3.id());
+        assert_ne!(g1.id(), g3.id());
+    }
